#include <iostream>
#include <fstream>
#include <string>

const unsigned int KEY = 0xDEADBEEF; // Fixed key for XOR encryption

std::string xorEncrypt(const std::string& password) {
    std::string encryptedPassword(password.size(), 0);
    for (size_t i = 0; i < password.size(); ++i) {
        encryptedPassword[i] = password[i] ^ KEY;
    }
    return encryptedPassword;
}

int main() {
    std::string password;
    std::cout << "Enter a password: ";
    std::cin >> password;

    std::string encryptedPassword = xorEncrypt(password);
    std::ofstream file("passwords.txt", std::ios::binary | std::ios::out);
    if (file.is_open()) {
        file << encryptedPassword;
        file.close();
    } else {
        std::cerr << "Unable to open the file." << std::endl;
    }

    return 0;
}